-	DryRun   bool      `json:"dry_run,omitempty"`
-	Anomalies []Anomaly `json:"anomalies,omitempty"`
+	Database      string        `json:"database"`
+	Closed        int           `json:"closed"`
+	ClosedEntries []ClosedEntry `json:"closed_entries,omitempty"`
